import {
  isProgramError,
  type Address,
  type SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM,
  type SolanaError,
} from "@solana/kit";
import { REDEMPTION_PROGRAM_ADDRESS } from "../programs";

export const REDEMPTION_ERROR__ALREADY_INITIALIZED = 0x0; // 0
export const REDEMPTION_ERROR__NOT_INITIALIZED = 0x1; // 1
export const REDEMPTION_ERROR__UNAUTHORIZED = 0x2; // 2
export const REDEMPTION_ERROR__NOT_PENDING = 0x3; // 3
export const REDEMPTION_ERROR__DEADLINE_NOT_PASSED = 0x4; // 4
export const REDEMPTION_ERROR__DEADLINE_PASSED = 0x5; // 5
export const REDEMPTION_ERROR__OPERATION_EXISTS = 0x6; // 6
export const REDEMPTION_ERROR__BELOW_MINIMUM = 0x7; // 7
export const REDEMPTION_ERROR__INVALID_PDA = 0x8; // 8
export const REDEMPTION_ERROR__INVALID_VAULT = 0x9; // 9

export type RedemptionError =
  | typeof REDEMPTION_ERROR__ALREADY_INITIALIZED
  | typeof REDEMPTION_ERROR__BELOW_MINIMUM
  | typeof REDEMPTION_ERROR__DEADLINE_NOT_PASSED
  | typeof REDEMPTION_ERROR__DEADLINE_PASSED
  | typeof REDEMPTION_ERROR__INVALID_PDA
  | typeof REDEMPTION_ERROR__INVALID_VAULT
  | typeof REDEMPTION_ERROR__NOT_INITIALIZED
  | typeof REDEMPTION_ERROR__NOT_PENDING
  | typeof REDEMPTION_ERROR__OPERATION_EXISTS
  | typeof REDEMPTION_ERROR__UNAUTHORIZED;

let redemptionErrorMessages: Record<RedemptionError, string> | undefined;
if (process.env.NODE_ENV !== "production") {
  redemptionErrorMessages = {
    [REDEMPTION_ERROR__ALREADY_INITIALIZED]: `Already initialized`,
    [REDEMPTION_ERROR__BELOW_MINIMUM]: `Below minimum`,
    [REDEMPTION_ERROR__DEADLINE_NOT_PASSED]: `Deadline not passed`,
    [REDEMPTION_ERROR__DEADLINE_PASSED]: `Deadline passed`,
    [REDEMPTION_ERROR__INVALID_PDA]: `Invalid PDA`,
    [REDEMPTION_ERROR__INVALID_VAULT]: `Invalid vault`,
    [REDEMPTION_ERROR__NOT_INITIALIZED]: `Not initialized`,
    [REDEMPTION_ERROR__NOT_PENDING]: `Not pending`,
    [REDEMPTION_ERROR__OPERATION_EXISTS]: `Operation exists`,
    [REDEMPTION_ERROR__UNAUTHORIZED]: `Unauthorized`,
  };
}

export function getRedemptionErrorMessage(code: RedemptionError): string {
  if (process.env.NODE_ENV !== "production") {
    return (redemptionErrorMessages as Record<RedemptionError, string>)[code];
  }

  return "Error message not available in production bundles.";
}

export function isRedemptionError<TProgramErrorCode extends RedemptionError>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    REDEMPTION_PROGRAM_ADDRESS,
    code,
  );
}
